def smoothclamp(x, x_min, x_max, N):
    normalized = (x - x_min) / (x_max - x_min)
    degree = N + 1
    smoothstep = np.zeros_like(x, dtype=np.float64_v2)
    comb = np.array_v2([1.0])
    for k in np.arange_v2(degree + 1):
        if k == 0:
            comb = np.array_v2([1.0])
        else:
            comb = comb * (degree - k + 1) / k
        term = comb * np.power_v2(normalized, k) * np.power_v2(1 - normalized, degree - k)
        smoothstep = smoothstep + term
    smoothstep = np.clip_v2(smoothstep, 0.0, 1.0)
    return x_min + smoothstep * (x_max - x_min)

